function revealSelectorList(): string {
  const declRe = /opacity\s*:\s*1\s*;\s*pointer-events\s*:\s*auto\s*;/;
  const m = CSS.match(declRe);
  if (!m || m.index === undefined) return '';
  // Walk back from m.index to the previous '}' to get the selector list.
  const before = CSS.slice(0, m.index);
  const lastBrace = before.lastIndexOf('}');
  // The selector list is between lastBrace+1 and m.index (where the '{' is).
  return CSS.slice(lastBrace + 1, m.index);
}
```

