/**
 * Returns the full selector list (text between the previous rule's closing `}`
 * and the opening `{`) of the REVEAL rule — the grouped rule whose declaration
 * block sets `opacity:1` and `pointer-events:auto`. Returns '' if none exists.
 *
 * Used to verify WHICH selectors participate in the .row-menu-btn reveal
 * (hover / keyboard-focus / aria-expanded) without depending on the exact
 * quote style of `[aria-expanded]`.
 */
function revealSelectorList(): string {
  const m = CSS.match(/opacity\s*:\s*1\s*;[\s\S]*?pointer-events\s*:\s*auto\s*;/);
  if (!m || m.index === undefined) return '';
  const upToDecl = CSS.slice(0, m.index);
  const openBrace = upToDecl.lastIndexOf('{');
  const prevClose = upToDecl.lastIndexOf('}', openBrace);
  return CSS.slice(prevClose + 1, openBrace);
}

/**
 * Returns the body (between the outer `{` … `}`) of the FIRST
 * `@media (hover: none) { … }` block, or '' if none exists. Brace-balanced so
 * nested rules are captured. Touch devices have no :hover, so the trigger's
 * hover-based reveal is unreachable there unless a @media (hover:none) override
 * (or a non-zero base opacity) makes it perceivable & operable.
 */
function mediaHoverNoneBody(): string {
  const open = CSS.search(/@media[^{]*\(\s*hover\s*:\s*none\s*\)[^{]*\{/);
  if (open < 0) return '';
  const braceIdx = CSS.indexOf('{', open);
  if (braceIdx < 0) return '';
  let i = braceIdx + 1;
  let depth = 1;
  let body = '';
  while (i < CSS.length && depth > 0) {
    const ch = CSS[i];
    if (ch === '{') depth++;
    else if (ch === '}') depth--;
    if (depth > 0) body += ch;
    i++;
  }
  return body;
}
```

